public class Main {

    public static void main(String[] args) throws IOException {
        String sourceDir = "/workspace/code-coverage-api-plugin/plugin/src/main/java";

        JavaParser parser = new JavaParser();

        // Keep iterating until no more changes are made (handles multi-level inheritance)
        boolean changed;
        int iteration = 0;
        do {
            changed = false;
            iteration++;
            System.out.println("Iteration " + iteration);

            Set<String> serializableClasses = new HashSet<>();

            // Collect all classes that are serializable (directly or through inheritance)
            try (Stream<Path> paths = Files.walk(Paths.get(sourceDir))) {
                paths.filter(Files::isRegularFile)
                     .filter(p -> p.toString().endsWith(".java"))
                     .forEach(p -> {
                         try {
                             collectSerializableClasses(parser, p, serializableClasses);
                         } catch (IOException e) {
                             System.err.println("Error processing " + p + ": " + e.getMessage());
                         }
                     });
            }

            // Add serialVersionUID to classes that need it
            try (Stream<Path> paths = Files.walk(Paths.get(sourceDir))) {
                paths.filter(Files::isRegularFile)
                     .filter(p -> p.toString().endsWith(".java"))
                     .forEach(p -> {
                         try {
                             if (processFile(parser, p, serializableClasses)) {
                                 changed = true;
                             }
                         } catch (IOException e) {
                             System.err.println("Error processing " + p + ": " + e.getMessage());
                         }
                     });
            }
        } while (changed);

        System.out.println("Transformation complete after " + iteration + " iterations!");
    }

